      "id": "alabama-cares-program",
      "name": "Alabama Cares Program",
      "shortName": "Alabama Cares",
      "tagline": "Free respite care, counseling, and support services for family caregivers of aging loved ones or disabled relatives.",
      "programType": "benefit",
      "complexity": "deep",
